        if node_attrs.get('name') == 'ju1.a4.m1' and 'EK_AGG_BLOCK' in node_attrs.get('type', []):
            target_node = node_id
            break

    # If target node not found, return empty list
    if target_node is None:
        return {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }

    # Helper function to recursively calculate total physical capacity
    def calculate_capacity(node_id):
        node_attrs = graph_copy.nodes[node_id]
        node_type = node_attrs.get('type', [])

        # Base case: if this is a PORT node, return its physical capacity
        if 'EK_PORT' in node_type:
            return node_attrs.get('physical_capacity_bps', 0)

        # Recursive case: sum capacity of all children connected via RK_CONTAINS
        total_capacity = 0
