    graph_copy.add_edge(parent_node, new_node_name, type='RK_CONTAINS')

    # Find all direct child nodes of the parent (via RK_CONTAINS edges)
    direct_children = []
    for u, v, edata in graph_copy.out_edges(parent_node, data=True):
        if edata.get('type') == 'RK_CONTAINS':
            direct_children.append(v)

    # Helper function to calculate total physical capacity of a node subtree
    def calculate_total_capacity(node):
        node_data = graph_copy.nodes[node]
