        # If this is a PORT node, return its physical capacity
        if 'EK_PORT' in node_types:
            return node_data.get('physical_capacity_bps', 0)

        # Otherwise, sum capacities of all contained child nodes
        total_capacity = 0
        for u, v, edata in graph_copy.out_edges(node, data=True):
            if edata.get('type') == 'RK_CONTAINS':
                total_capacity += calculate_total_capacity(v)

        return total_capacity

